// frontend/src/draggableNode.js
import React from "react";

/**
 * DraggableNode
 * - type: node type string (e.g., "deleteNode")
 * - label: visible label in the toolbar
 * - nodeProps (optional): extra payload to include on drag (className, data, etc.)
 */
export const DraggableNode = ({ type, label, nodeProps = {} }) => {
  const onDragStart = (event, nodeType) => {
    const appData = { nodeType };

    // allow toolbar to override payload via nodeProps
    if (nodeProps.className) appData.className = nodeProps.className;
    if (nodeProps.data) appData.data = nodeProps.data;

    // fallback behavior: special-case deleteNode, otherwise send label
    if (!appData.data) {
      if (nodeType === "deleteNode") {
        appData.className = appData.className || "delete-node";
        appData.data = {
          candidates: [],
          onDelete: () => {},
          canDeleteTool: false,
          ...nodeProps.data,
        };
      } else {
        appData.data = { label, ...nodeProps.data };
      }
    }

    event.currentTarget.style.cursor = "grabbing";
    event.dataTransfer.setData("application/reactflow", JSON.stringify(appData));
    event.dataTransfer.effectAllowed = "move";
  };

  return (
    <div
      className={type}
      onDragStart={(event) => onDragStart(event, type)}
      onDragEnd={(event) => (event.currentTarget.style.cursor = "grab")}
      style={{
        cursor: "grab",
        minWidth: "80px",
        height: "60px",
        display: "flex",
        alignItems: "center",
        borderRadius: "8px",
        backgroundColor: "#1C2536",
        justifyContent: "center",
        flexDirection: "column",
      }}
      draggable
    >
      <span style={{ color: "#fff" }}>{label}</span>
    </div>
  );
};
